#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int X, Y, K, N;
        scanf("%d %d %d %d", &X, &Y, &K, &N);
        int found = 0;
        for (int i = 0; i < N; i++) {
            int Pi, Ci;
            scanf("%d %d", &Pi, &Ci);
            if (Pi >= X - Y && Ci <= K) {
                found = 1;
                break;
            }
        }
        if (found) {
            printf("LuckyChef\n");
        } else {
            printf("UnluckyChef\n");
        }
    }
    return 0;
}

