        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int X = sc.nextInt();
            int Y = sc.nextInt();
            int K = sc.nextInt();
            int N = sc.nextInt();
            boolean found = false;
            for (int i = 0; i < N; i++) {
                int Pi = sc.nextInt();
                int Ci = sc.nextInt();
                if (Pi >= X - Y && Ci <= K) {
                    found = true;
                    break;
                }
            }
            if (found) {
                System.out.println("LuckyChef");
            } else {
                System.out.println("UnluckyChef");
            }
        }
    }
}

